UPDATE speakers SET themes = (SELECT ARRAY(SELECT DISTINCT unnest(array_replace(array_replace(array_replace(array_replace(themes, 'Excellence', 'Performance'), 'Performance et croissance', 'Performance'), 'Stratégie d''entreprise', 'Stratégie'), 'Progrès', 'Innovation')))) WHERE themes && ARRAY['Excellence','Performance et croissance','Stratégie d''entreprise','Progrès']::text[]; UPDATE speakers SET themes = (SELECT ARRAY(SELECT DISTINCT unnest(array_remove(themes, 'Innovation et transformation') || ARRAY['Innovation','Transformation']))) WHERE 'Innovation et transformation' = ANY(themes); UPDATE speakers SET themes = (SELECT ARRAY(SELECT DISTINCT unnest(array_remove(themes, 'Leadership et management') || ARRAY['Leadership','Management']))) WHERE 'Leadership et management' = ANY(themes);